-- Import Arabic values. Existing values, regardless of status, remain untouched.
insert into public.localization_values(key_id,language_code,translated_text,status,version,approved_at)
select k.id,'ar',i.ar_text,'approved',1,now()
from import_data i
join public.localization_keys k on k.translation_key=i.translation_key
where i.ar_text is not null and btrim(i.ar_text)<>''
on conflict (key_id,language_code) do nothing;

