-- Queue every current key for future Filipino review. No machine translation is generated.
insert into public.localization_queue(translation_key,source_language,source_text,target_language,suggested_text,module,status)
select i.translation_key,'ar',i.ar_text,'fil',null,i.module,'pending'
from import_data i
where i.ar_text is not null
  and not exists (
    select 1 from public.localization_values v
    join public.localization_keys k on k.id=v.key_id
    where k.translation_key=i.translation_key and v.language_code='fil' and v.status='approved'
  )
on conflict (source_text,source_language,target_language,module) do nothing;

commit;

